    Value(1.62)
);
Set(
    gblAppAutoload,
    true
);
Set(
    gblAppLoadOffline,
    !(Param("offlinemode")="false")
);
Set(
    gblAppAutoAdvance,
    true
);
Set(
    gblDateCurrent,
    Today()
);
ClearCollect(
    colAUDRecords,
    FirstN(Table({Type: "A", RecordRef: GUID(), Job: GUID(), Operation: "A"}),0)
);
// App Icons
